+        if targets.is_empty() {
+            return None;
+        }
+
+        // Filter to valid targets that can accept the payload
+        let valid_indices: Vec<usize> = targets
+            .iter()
+            .enumerate()
+            .filter(|(_, t)| t.can_accept(&state.payload.drag_type))
+            .map(|(i, _)| i)
+            .collect();
