+impl Dialog {
+    /// Create an alert dialog (message + OK).
+    pub fn alert(title: impl Into<String>, message: impl Into<String>) -> Self {
+        Self {
+            title: title.into(),
+            message: message.into(),
+            buttons: vec![DialogButton::new("OK", "ok").primary()],
+            config: DialogConfig {
+                kind: DialogKind::Alert,
