+            message: message.into(),
+            buttons: vec![
+                DialogButton::new("OK", "ok").primary(),
+                DialogButton::new("Cancel", "cancel"),
+            ],
+            config: DialogConfig {
+                kind: DialogKind::Prompt,
+                ..Default::default()
