+
+        // Restore snapshot
+        assert!(tree.restore_snapshot(&*snapshot));
+
+        // Verify restored state
+        assert!(tree.is_node_expanded(&[0])); // a back to expanded
+        assert!(!tree.is_node_expanded(&[1])); // b back to collapsed
+    }
